package ir.tahamohamadi.resume; import ir.tahamohamadi.common.domain.*; import org.springframework.data.jpa.repository.*; import org.springframework.data.repository.query.Param; import java.util.*; public interface ResumeEntryTranslationRepository extends JpaRepository<ResumeEntryTranslation,UUID>{ @Query("select t from ResumeEntryTranslation t join t.entry e where t.languageCode=:language and t.deletedAt is null and e.deletedAt is null and e.status='PUBLISHED' order by e.sortOrder,e.startedOn desc,e.id") List<ResumeEntryTranslation> findPublishedByLanguage(@Param("language") LanguageCode language); }
